#include <stdio.h>

/* Struktura za datum */
typedef struct {
    int dan, mjesec, godina;
} Datum;

/* Struktura Proizvod sa dva datuma */
typedef struct {
    char naziv[30];
    double cijena;
    Datum datum_proizvodnje;
    Datum datum_isteka;
} Proizvod;

/* Funkcija za unos datuma */
Datum unesi_datum() {
    Datum d;
    printf("Unesite datum (dan mjesec godina): ");
    scanf("%d %d %d", &d.dan, &d.mjesec, &d.godina);
    return d;
}

/* Funkcija za unos proizvoda */
Proizvod unesi_proizvod() {
    Proizvod p;

    printf("Unesite naziv proizvoda: ");
    scanf("%s", p.naziv);

    printf("Unesite cijenu: ");
    scanf("%lf", &p.cijena);

    printf("Unesite datum proizvodnje:\n");
    p.datum_proizvodnje = unesi_datum();

    printf("Unesite datum isteka:\n");
    p.datum_isteka = unesi_datum();

    return p;
}

/* Funkcija za ispis proizvoda */
void ispisi_proizvod(Proizvod p) {
    printf("Naziv: %s\n", p.naziv);
    printf("Cijena: %.2f\n", p.cijena);

    printf("Datum proizvodnje: %d.%d.%d\n",
           p.datum_proizvodnje.dan,
           p.datum_proizvodnje.mjesec,
           p.datum_proizvodnje.godina);

    printf("Datum isteka: %d.%d.%d\n",
           p.datum_isteka.dan,
           p.datum_isteka.mjesec,
           p.datum_isteka.godina);
}

int main() {
    Proizvod p1 = unesi_proizvod();

    printf("Ispis proizvoda \n");
    ispisi_proizvod(p1);

    return 0;
}
